const dls = new Map();
const tryNum = new Map();
const taskActions = new Map();
const tasks = new Map();
export const checkList = (list, musicInfo, quality, ext) => {
    return list.some((s) => s.id === musicInfo.id && (s.metadata.quality === quality || s.metadata.ext === ext));
};
